import React, { useEffect, useRef, useState } from 'react';
import styles from './VoucherFormToolbar.module.css';

export interface ToolbarOverflowItem {
  key: string;
  node: React.ReactNode;
}

interface ToolbarOverflowMenuProps {
  testIdPrefix: string;
  items: ToolbarOverflowItem[];
}

export const ToolbarOverflowMenu: React.FC<ToolbarOverflowMenuProps> = ({ testIdPrefix, items }) => {
  const [open, setOpen] = useState(false);
  const wrapRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!open) return undefined;
    const onDocClick = (event: MouseEvent) => {
      if (wrapRef.current && !wrapRef.current.contains(event.target as Node)) {
        setOpen(false);
      }
    };
    const timer = window.setTimeout(() => {
      document.addEventListener('click', onDocClick);
    }, 0);
    return () => {
      clearTimeout(timer);
      document.removeEventListener('click', onDocClick);
    };
  }, [open]);

  if (items.length === 0) return null;

  return (
    <div className={styles.overflowWrap} ref={wrapRef}>
      <button
        type="button"
        className={styles.toolbarBtn}
        data-testid={`${testIdPrefix}-toolbar-more`}
        aria-expanded={open}
        aria-haspopup="menu"
        onClick={() => setOpen((v) => !v)}
      >
        <i className="fas fa-ellipsis-h" aria-hidden /> Thêm
      </button>
      {open && (
        <div
          className={styles.overflowMenu}
          role="menu"
          data-testid={`${testIdPrefix}-toolbar-more-menu`}
        >
          {items.map((item) => (
            <div
              key={item.key}
              className={styles.overflowMenuItem}
              role="none"
              data-testid={`${testIdPrefix}-toolbar-more-${item.key}`}
              onClick={() => setOpen(false)}
              onKeyDown={() => {}}
            >
              {item.node}
            </div>
          ))}
        </div>
      )}
    </div>
  );
};
